// ── Normalizar entrada según el tipo de acción ──────────────────────────
let desde, hasta;

const action = msg.payload && msg.payload.action;
const value  = msg.payload && msg.payload.value;

if (action === 'set_horas') {
    const horas = Math.min(value, 720);
    hasta = Date.now();
    desde = hasta - (horas * 3600000);
} else if (action === 'save_state' && value) {
    const state = value;
    if (state.tpAbsoluto && state.tpFrom && state.tpTo) {
        desde = new Date(state.tpFrom).getTime();
        hasta = new Date(state.tpTo).getTime();
    } else {
        const horas = state.rangoActivo || 1;
        hasta = Date.now();
        desde = hasta - (horas * 3600000);
    }
} else {
    return null;
}

if (!desde || !hasta || hasta <= desde) return null;

// ── Generar series mock ──────────────────────────────────────────────────
const duracion     = hasta - desde;
const MAX_PUNTOS   = 2000;
const MIN_INTERVALO = 10000;
const intervalo    = Math.max(MIN_INTERVALO, Math.floor(duracion / MAX_PUNTOS));
const puntos       = Math.min(MAX_PUNTOS, Math.floor(duracion / intervalo));

const mkData = (fn, decimals = 3) => Array.from({ length: puntos }, (_, i) => [
    desde + i * intervalo,
    parseFloat(fn(i).toFixed(decimals))
]);

const series = [
    {
        name: 'Circuito A · kW', metric: 'kW', type: 'line',
        yAxisIndex: 0,
        data: mkData(i => 1.2 + Math.sin(i / 8) * 0.4),
        smooth: true, connectNulls: false,
        lineStyle: { width: 1, color: '#58a6ff' },
        itemStyle: { color: '#58a6ff' }
    },
    {
        name: 'Circuito B · kW', metric: 'kW', type: 'line',
        yAxisIndex: 0,
        data: mkData(i => 0.8 + Math.cos(i / 6) * 0.3),
        smooth: true, connectNulls: false,
        lineStyle: { width: 1, color: '#3fb950' },
        itemStyle: { color: '#3fb950' }
    },
    {
        name: 'Circuito C · kW', metric: 'kW', type: 'line',
        yAxisIndex: 0,
        data: mkData(i => 0.5 + Math.sin(i / 10 + 1) * 0.2),
        smooth: true, connectNulls: false,
        lineStyle: { width: 1, color: '#f78166' },
        itemStyle: { color: '#f78166' }
    },
    {
        name: 'Temperatura · °C', metric: '°C', type: 'line',
        yAxisIndex: 1,
        data: mkData(i => 22 + Math.sin(i / 12) * 1.5, 1),
        smooth: true, connectNulls: false,
        lineStyle: { width: 1, color: '#F2CC0C' },
        itemStyle: { color: '#F2CC0C' }
    },
    {
        name: 'Circuito A · V', metric: 'V', type: 'line',
        yAxisIndex: 2,
        data: mkData(i => 220 + Math.sin(i / 15) * 1.5, 1),
        smooth: true, connectNulls: false,
        lineStyle: { width: 1, color: '#d2a8ff' },
        itemStyle: { color: '#d2a8ff' }
    },
    {
        name: 'Circuito A · A', metric: 'A', type: 'line',
        yAxisIndex: 3,
        data: mkData(i => 5.5 + Math.sin(i / 8) * 1.8, 2),
        smooth: true, connectNulls: false,
        lineStyle: { width: 1, color: '#ffa657' },
        itemStyle: { color: '#ffa657' }
    },
    {
        name: 'Red · Hz', metric: 'Hz', type: 'line',
        yAxisIndex: 1,
        data: mkData(i => 50 + (Math.sin(i / 5) * 0.03), 2),
        smooth: false, connectNulls: false,
        lineStyle: { width: 1, color: '#79c0ff' },
        itemStyle: { color: '#79c0ff' }
    },
    {
        name: 'Circuito A · cos φ', metric: 'cos φ', type: 'line',
        yAxisIndex: 5,
        data: mkData(i => 0.914 + Math.sin(i / 20) * 0.01, 3),
        smooth: true, connectNulls: false,
        lineStyle: { width: 1, color: '#56d364' },
        itemStyle: { color: '#56d364' }
    }
];

const colLabels = {
    'Circuito A': 'col-circuito-a',
    'Circuito B': 'col-circuito-b',
    'Circuito C': 'col-circuito-c',
    'Temperatura': 'col-temperatura',
    'Red': 'col-red'
};

// ── Status ───────────────────────────────────────────────────────────────
const mins = Math.round(duracion / 60000);
node.status({ fill: 'green', shape: 'dot', text: `${puntos} pts · ${mins} min` });

msg.topic   = 'insight/data';
msg.payload = { series, colLabels };
return msg;

